              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: [
                Text('-1', style: TextStyle(fontSize: 10, color: Colors.grey)),
                Text('0', style: TextStyle(fontSize: 10, color: Colors.grey)),
                Text('+1', style: TextStyle(fontSize: 10, color: Colors.grey)),
