              const SizedBox(width: 12),
              _StatCard(
                title: 'Streak',
                value: '$streak',
                subtitle: streak == 1 ? 'day' : 'days',
                color: Colors.orange,
              ),
            ],
          ),
          const SizedBox(height: 24),

          // 14-day trend
          const Text(
            '14-Day Mood Trend',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
